from tabulate import tabulate

import numpy as np

from mpl_toolkits import mplot3d
import matplotlib.colors as mcolors
import matplotlib.pyplot as plt
from matplotlib.colors import TABLEAU_COLORS, same_color
%matplotlib ipympl

R = 8
r = 3
w = .6
h = .6

# Pattern instructions
N = round(r * np.pi/h)
st_count = [0]*(int(N)+1)
pattern = [0]*(int(N)+1)
row = [0]*(int(N)+1)
for n in range(int(N)+1):
    st_count[n]=round(2*np.pi*(R-r*np.cos(n*np.pi/int(N)))/w)
    row[n] = n #"Row "+str(n)+": "+str(st_count[n])+" st."
    plt.clf()

# Pattern model
fig = plt.figure(figsize = (10,10),label=' ')
ax = plt.axes(projection='3d')
ax.grid()

c = [
    'gray',
    'xkcd:bright pink',
    'xkcd:tangerine',
    'xkcd:aqua',
    'xkcd:violet',
    'xkcd:light blue',
    'xkcd:magenta',
    'xkcd:yellow'
]  

colours = [0]*(N+1)

# UPPER
for n in range(int(N)+1):
    colours[n] = [c[0] for i in range(st_count[n])]
    for k in range(0,st_count[n]):
        theta = (n+.5)*np.pi/N
        phi = (k+.5)*2*np.pi/st_count[n] # slight offset to better reflect crochet stitch distribution

        m=-(2/3)*N/st_count[n]
        L1 = m*k+(2/3)*N
        L2 = m*k+(4/3)*N
        L3 = m*k+2*N
        if phi <= np.pi/4:
            if n<=L1:
                colours[n][k] = c[1]
            elif L1<=n<=L2:
                colours[n][k] = c[2]


        elif np.pi/4 <= phi <= 3*np.pi/4:

            if n<=L1:
                colours[n][k] = c[1]
            elif L1<=n<=L2:
                colours[n][k] = c[3]


        elif 3*np.pi/4 <= phi <= np.pi:

            if n<=L1:
                colours[n][k] = c[4]
            elif L1<=n<=L2:
                colours[n][k] = c[3]


        elif np.pi <= phi <= 5*np.pi/4:

            if n<=L1:
                colours[n][k] = c[4]
            elif L1<=n<=L2:
                colours[n][k] = c[5]
            elif L2<=n:
                colours[n][k] = c[6]


        elif 5*np.pi/4 <= phi <= 3*np.pi/2:

            if n<=L1:
                colours[n][k] = c[4]
            elif L1<=n<=L2:
                colours[n][k] = c[5]
            elif L2<=n:
                colours[n][k] = c[2]


        elif 3*np.pi/2 <= phi <= 7*np.pi/4:

            if n<=L1:
                colours[n][k] = c[7]
            elif L1<=n<=L2:
                colours[n][k] = c[5]
            elif L2<=n:
                colours[n][k] = c[2]


        elif 3*np.pi/2 <= phi <= 2*np.pi:

            if n<=L1:
                colours[n][k] = c[7]
            elif L1<=n<=L2:
                colours[n][k] = c[1]
            elif L2<=n:
                colours[n][k] = c[2]

        u = np.linspace((n-.5)*np.pi/N, (n+.5)*np.pi/N, 2)
        v = np.linspace((k-.5)*2*np.pi/st_count[n], (k+.5)*2*np.pi/st_count[n], 2)
        u, v = np.meshgrid(u, v)
        x = (R-r*np.cos(u))*np.cos(v)
        y = (R-r*np.cos(u))*np.sin(v)
        z = r*np.sin(u)
        ax.plot_surface(x, y, z, color=colours[n][k], edgecolor='black', linewidth=.1)

